from fastapi import FastAPI
from pydantic import BaseModel

app = FastAPI()

# Дані в пам'яті
items = []
counter = 0

class Item(BaseModel):
    name: str
    description: str = ''
    price: float

@app.get('/items')
def list_items():
    return items

@app.post('/items')
def create_item(item: Item):
    global counter
    counter += 1
    new_item = {'id': counter, **item.dict()}
    items.append(new_item)
    return new_item

@app.get('/items/{item_id}')
def get_item(item_id: int):
    for item in items:
        if item['id'] == item_id:
            return item
    return {'error': 'Not found'}

@app.delete('/items/{item_id}')
def delete_item(item_id: int):
    global items
    items = [i for i in items if i['id'] != item_id]
    return {'ok': True}

print('API створено!')
print('Endpoints: GET /items, POST /items, GET /items/{id}, DELETE /items/{id}')
